   434|export async function routeDeploymentCommand(message: string): Promise<string | null> {
   435|  const trimmed = message.trim();
   436|  if (!trimmed.startsWith('/')) return null;
   437|
   438|  // Extract the command (first word)
   439|  const command = trimmed.split(/\s+/)[0].toLowerCase();
   440|
   441|  const handler = COMMAND_MAP[command];
   442|  if (!handler) return null;
   443|
